        echo "Please enter a valid integer.";
        return false;
    }

    // Calculate the square root
    $sqrt = sqrt($num);

    // Check if the square root is an integer
    if (floor($sqrt) == $sqrt) {
        echo "$num is a perfect square.";
    } else {
        echo "$num is not a perfect square.";
